import{_ as t,c as r,o as a,af as i}from"./chunks/framework.DcbXK6Cz.js";const o="/hajimi/NO.2.png",n="/hajimi/NO.3.png",l="/hajimi/NO.4.png",s="/hajimi/NO.5.png",d="/hajimi/NO.6.png",p="/hajimi/NO.7.png",h="/hajimi/NO.8.png",c="/hajimi/NO.9.png",g="/hajimi/NO.10.jpg",j=JSON.parse('{"title":"Render适用于Hajimi轮询项目的部署教程","description":"","frontmatter":{},"headers":[],"relativePath":"guide/hajimi/polling.md","filePath":"guide/hajimi/polling.md"}'),m={name:"guide/hajimi/polling.md"};function b(u,e,_,S,f,k){return a(),r("div",null,e[0]||(e[0]=[i('<h1 id="render适用于hajimi轮询项目的部署教程" tabindex="-1">Render适用于Hajimi轮询项目的部署教程 <a class="header-anchor" href="#render适用于hajimi轮询项目的部署教程" aria-label="Permalink to &quot;Render适用于Hajimi轮询项目的部署教程&quot;">​</a></h1><blockquote><p>本教程适用于在 <a href="https://dashboard.render.com" target="_blank" rel="noreferrer">Render</a> 平台上零基础部署 <a href="https://github.com/wyeeeee/hajimi" target="_blank" rel="noreferrer">Hajimi轮询项目</a>。<br> 包含必要环境变量说明、注意事项与常见问题解答。</p></blockquote><hr><h2 id="前置准备" tabindex="-1">前置准备 <a class="header-anchor" href="#前置准备" aria-label="Permalink to &quot;前置准备&quot;">​</a></h2><ul><li><strong>科学上网</strong>：建议开启 “TUN模式” 和 “全局模式”，确保IP干净，避免Render绑卡验证。</li><li><strong>相关工具/平台</strong>： <ul><li><a href="https://ai.google.dev/gemini-api/docs/models?hl=zh-cn" target="_blank" rel="noreferrer">Gemini模型列表</a></li><li><a href="https://console.cloud.google.com/projectcreate" target="_blank" rel="noreferrer">Gemini创建项目</a></li><li><a href="https://aistudio.google.com/app/apikey" target="_blank" rel="noreferrer">Gemini获取秘钥</a></li><li><a href="https://github.com/wyeeeee/hajimi/blob/main/app/config/settings.py" target="_blank" rel="noreferrer">环境变量参考</a></li></ul></li></ul><hr><h2 id="step-1-登录-render" tabindex="-1">Step 1. 登录 Render <a class="header-anchor" href="#step-1-登录-render" aria-label="Permalink to &quot;Step 1. 登录 Render&quot;">​</a></h2><p>访问 <a href="https://dashboard.render.com" target="_blank" rel="noreferrer">Render官网</a>，注册/登录账号。</p><blockquote><p>登录遇到问题时，尝试关闭TUN，或切换代理“规则模式”！</p></blockquote><p><img src="'+o+'" alt="Render登录页面"></p><hr><h2 id="step-2-创建-web-service" tabindex="-1">Step 2. 创建 Web Service <a class="header-anchor" href="#step-2-创建-web-service" aria-label="Permalink to &quot;Step 2. 创建 Web Service&quot;">​</a></h2><ol><li>首页选择 <strong>Web Services</strong><br><img src="'+n+'" alt="Web Service选项"></li><li>选择 <strong>Public Git Repository</strong>，填入仓库地址：<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://github.com/wyeeeee/hajimi</span></span></code></pre></div><img src="'+l+'" alt="填写仓库地址"></li></ol><hr><h2 id="step-3-配置服务参数" tabindex="-1">Step 3. 配置服务参数 <a class="header-anchor" href="#step-3-配置服务参数" aria-label="Permalink to &quot;Step 3. 配置服务参数&quot;">​</a></h2><ol><li><p><strong>Region</strong> 推荐选择 <code>Singapore</code>（亚洲更快）。<br><img src="'+s+'" alt="选择Region"></p></li><li><p><strong>Instance Type</strong> 选择 <code>Free</code>（免费）。 <img src="'+d+'" alt="Instance Type"></p></li><li><p><strong>环境变量添加</strong><br> 按下表填写，未涉及项可留空：</p><table tabindex="0"><thead><tr><th>变量名</th><th>是否必填</th><th>作用及说明</th><th>示例值</th></tr></thead><tbody><tr><td>WEB_PASSWORD</td><td>可选</td><td>WebUI前端配置密码（如忽略，值同PASSWORD）</td><td>web-yuhuan</td></tr><tr><td>PASSWORD</td><td>必填</td><td>API调用密钥（后续可改）</td><td>key-yuhuan</td></tr><tr><td>WHITELIST_MODELS</td><td>可选</td><td>限定可用模型ID，逗号分隔</td><td>gemini-2.5-flash,gemini-2.5-pro</td></tr><tr><td>GEMINI_API_KEYS</td><td>可选</td><td>Gemini API密钥，逗号分隔</td><td>AIzaSy...</td></tr><tr><td>TZ</td><td>可选</td><td>日志/统计参考时区</td><td>Asia/Shanghai</td></tr></tbody></table><p><img src="'+p+'" alt="环境变量配置"></p></li></ol><hr><h2 id="step-4-部署与访问" tabindex="-1">Step 4. 部署与访问 <a class="header-anchor" href="#step-4-部署与访问" aria-label="Permalink to &quot;Step 4. 部署与访问&quot;">​</a></h2><ol><li>点击 <strong>Deploy Web Service</strong><br><img src="'+h+'" alt="部署服务按钮"></li><li>状态变为绿色“Live”后，复制页面URL，即为WebUI入口和API端点。<br><img src="'+c+'" alt="URL与状态"></li></ol><hr><h2 id="step-5-sillytavern-连接配置示例" tabindex="-1">Step 5. SillyTavern 连接配置示例 <a class="header-anchor" href="#step-5-sillytavern-连接配置示例" aria-label="Permalink to &quot;Step 5. SillyTavern 连接配置示例&quot;">​</a></h2><ul><li><strong>API类型</strong>：聊天补全</li><li><strong>聊天补全来源</strong>：自定义（兼容OpenAI）</li><li><strong>端点URL</strong>：<code>https://你的实例.onrender.com/v1</code></li><li><strong>API密钥</strong>：与 PASSWORD 环境变量一致</li><li><strong>输入模型名</strong>：如 <code>gemini-2.5-pro</code></li><li><strong>连接状态</strong>：绿色为正常</li><li><strong>自动连接</strong>：建议开启</li></ul><p><img src="'+g+'" alt="酒馆连接配置"></p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><ul><li>Render 免费服务15分钟未访问将自动休眠，再次访问需等待空间激活（约1分钟）。</li><li>推荐结合保活方案，见文档“<a href="/guide/cronjob/keepalive.html">Cron-Job保活配置</a>”。</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span></code></pre></div>',27)]))}const P=t(m,[["render",b]]);export{j as __pageData,P as default};
